module RefModule (
    input wire clk,
    input wire reset,
    input wire serial_in,
    output reg [7:0] parallel_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset)
            parallel_out <= 8'b00000000;
        else
            parallel_out <= {parallel_out[6:0], serial_in};
    end

endmodule
